public class ComplexityAnalyzer {

    // O(1): returns first element regardless of array size
    public int constantOp(int[] arr) {
        if (arr == null || arr.length == 0) return -1;
        return arr[0]; // always one operation
    }

    // O(n): counts operations while summing the array
    public long linearOps(int n) {
        long ops = 0;
        long sum = 0;
        for (int i = 0; i < n; i++) {
            sum += i;
            ops++;
        }
        return ops;
    }

    // O(n^2): counts operations in nested loop
    public long quadraticOps(int n) {
        // TODO: implement nested loop, count and return operation count
        return 0;
    }

    public void printGrowthTable(int[] sizes) {
        System.out.printf("%-10s %-12s %-12s %-14s%n", "n", "O(1)", "O(n)", "O(n^2)");
        for (int n : sizes) {
            System.out.printf("%-10d %-12d %-12d %-14d%n",
                n, 1, linearOps(n), quadraticOps(n));
        }
    }

    public static void main(String[] args) {
        ComplexityAnalyzer ca = new ComplexityAnalyzer();
        ca.printGrowthTable(new int[]{1, 10, 100});
    }
}

public class SpaceComplexityDemo {

    // O(1) space - only uses a fixed number of variables
    public int constantSpace(int[] arr) {
        int max = arr[0];
        for (int v : arr) {
            if (v > max) max = v;
        }
        return max; // auxiliary space = O(1)
    }

    // O(n) space - creates a copy of the input
    public int[] linearSpace(int n) {
        int[] result = new int[n];
        for (int i = 0; i < n; i++) result[i] = i * i;
        return result; // auxiliary space = O(n)
    }

    // O(n^2) space - creates an n x n matrix
    public int[][] quadraticSpace(int n) {
        // TODO: create n x n matrix, fill [i][j] = i * n + j
