    }

    public void printSpaceUsage(int n) {
        int[] linear = linearSpace(n);
        int[][] quad = quadraticSpace(n);
        System.out.println("n = " + n);
        System.out.println("O(1) auxiliary slots: 2");
        System.out.println("O(n) auxiliary slots: " + linear.length);
        System.out.println("O(n^2) auxiliary slots: " + (quad.length * quad[0].length));
    }

    public static void main(String[] args) {
        SpaceComplexityDemo demo = new SpaceComplexityDemo();
        demo.printSpaceUsage(5);
        demo.printSpaceUsage(10);
    }
}

public class BigOClassifier {

    public String classify(long ops, int n) {
        if (n <= 1) return "O(1)";

        double logN = Math.log(n) / Math.log(2); // log base 2
        double ratio = (double) ops / n;

        if (ops <= 2) return "O(1)";             // constant
        if (ops <= logN * 1.5) return "O(log n)"; // logarithmic
        if (ratio <= 1.5) return "O(n)";          // linear
        if (ratio <= logN * 1.5) return "O(n log n)"; // linearithmic
        return "O(n^2)";                          // quadratic (fallback)
    }

